  ('diplomatic-20fe77d5-moex-00484', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-111-c655adf3', 'sub-diplomatic-20fe77d5-04', NULL, 'single_choice', '關於憲法第8條人身自由之保障主體，下列敘述何者正確？', '["憲法第8條之人身自由為國民權，僅保障我國國民", "憲法第8條之人身自由，除保障我國國民，亦保障外國人", "憲法第8條之人身自由，亦保障外國人，但以我國之邦交國國民為限", "憲法第8條之人身自由，亦保障外國人，但以持有我國永久居留證者為限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:36+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00485', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-111-c655adf3', 'sub-diplomatic-20fe77d5-04', NULL, 'single_choice', '社會秩序維護法第80條第1項第1款就意圖得利與人姦、宿者，處3日以下拘留或新臺幣3萬元以下罰鍰 之規定，司法院釋字第666號解釋是以何種理由宣告違憲？', '["性交易行為仍屬憲法第22條所保障之基本權利，立法者不得以善良風俗為由禁止", "以主觀上有無意圖得利，作為是否處罰之差別待遇標準，與立法目的欠缺實質關聯，違反平等原則", "就迫於社會經濟弱勢而從事性交易之女性，處以拘留或罰鍰之行政罰，已逾越必要程度，違反比例 原則", "人民用以謀生的經濟活動，都受憲法職業自由的同等保障，系爭規定侵害性交易服務者的工作權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:36+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00486', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-111-c655adf3', 'sub-diplomatic-20fe77d5-04', NULL, 'single_choice', '關於憲法中所規定人民的義務，下列敘述何者錯誤？', '["人民有依法律納稅之義務，即「租稅法定主義」", "人民有依法律服兵役之義務，立法者可於兵役法中規定女子亦須服兵役", "憲法規定之受國民教育義務包括高級中等教育", "人民有受國民教育的義務，而此亦屬人民的權利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:36+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00487', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-111-c655adf3', 'sub-diplomatic-20fe77d5-04', NULL, 'single_choice', '姓名條例規定，命名文字字義粗俗不雅，得申請改名，此係基於保障人民之何種基本權利？', '["人性尊嚴", "人格權", "隱私權", "資訊自主權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:36+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00488', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-111-c655adf3', 'sub-diplomatic-20fe77d5-04', NULL, 'single_choice', '依據憲法學理與實務見解，人民主張下列何種行為侵害其基本權利時，司法院大法官或憲法法庭得予 受理？', '["不利確定終局裁判所適用之桃園市自治條例", "不利確定終局裁判所適用之桃園地方法院有罪判決", "不利確定終局裁判所適用之桃園地方法院無罪判決", "不利確定終局裁判未適用之桃園市自治規則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:36+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00489', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-111-c655adf3', 'sub-diplomatic-20fe77d5-04', NULL, 'single_choice', '依據司法院大法官解釋，下列敘述何者錯誤？', '["根據釋字第791號解釋，關於撤回通姦罪告訴效力不及於相姦人之差別待遇，是否符合平等權保障， 手段與立法目的間採實質關聯基準", "根據釋字第791號解釋，關於性自主權與個人人格有不可分離關係之限制規範，是否合於比例原則， 適用較為嚴格之審查基準", "根據釋字第767號解釋，關於社會補償之立法，採取中度之審查基準", "根據釋字第799號解釋，對性侵害受處分人之人身自由予以限制，是否違反比例原則，採嚴格審查 標準"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:36+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-20fe77d5-moex-00490', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-111-c655adf3', 'sub-diplomatic-20fe77d5-04', NULL, 'single_choice', '關於行政機關之組織，下列敘述何者非憲法之明文規定？', '["行政院之組織，應以法律定之", "應以行政院為行政層級中之最高行政機關", "立法院不得於作用法中規定具組織法性質之規範", "行政院所屬各級機關之設置與組織，立法院得以準則性法律，為框架性規範"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:36+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
